arguments.file_text:
@page "/catalog"
@rendermode InteractiveServer
@namespace sv_8c45f4462d0241aeb8c7772b8f322879.Components.Pages
@using sv_8c45f4462d0241aeb8c7772b8f322879.Components.Catalog
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-4">Product Catalog</h3>

@if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-3">
            <CatalogSidebar Categories="categories"
                            OnApplyFilters="HandleApplyFilters"
                            OnClearFilters="HandleClearFilters" />
        </div>
        <div class="col-md-9">
            @if (isLoading)
            {
                <div class="d-flex justify-content-center align-items-center" style="min-height: 200px;">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading...</span>
                    </div>
                </div>
            }
            else if (result is not null && result.Items.Count > 0)
            {
                <CatalogToolbar SortBy="@sortBy"
                                Page="currentPage"
                                PageSize="PageSize"
                                TotalCount="result.TotalCount"
                                OnSortChanged="HandleSortChanged" />

                <ProductGrid Products="result.Items"
                             OnProductSelected="HandleProductSelected"
                             OnAddToCart="HandleAddToCart" />

                <CatalogPagination Page="currentPage"
                                   TotalCount="result.TotalCount"
                                   PageSize="PageSize"
                                   OnPageChanged="HandlePageChanged" />
            }
            else
            {
                <div class="text-center text-muted py-5">
                    <h5>No products found</h5>
                    <p>Try adjusting your filters.</p>
                </div>
            }
        </div>
    </div>
}

@code {
    private const int PageSize = 12;

    private List<string> categories = [];
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private PagedResult<Product>? result;
    private bool isLoading = true;
    private string? errorMessage;

    /// <summary>
    /// Raised when a product card is clicked so the parent/host can navigate to a detail page.
    /// </summary>
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            categories = await ProductService.GetCategoriesAsync();
            result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleApplyFilters(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleClearFilters()
    {
        currentFilter = new ProductFilter(null, null, null, false);
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder — integrate with cart service
        return Task.CompletedTask;
    }

    private async Task RetryLoad() => await LoadDataAsync();
}

